INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Continuous Integration$q$, $q$Cloud-hosted or self-hosted build pipelines with caching, parallelization and test intelligence that runs only the tests affected by a given code change.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Continuous Delivery and GitOps$q$, $q$Deploys to Kubernetes, VM, serverless and traditional infrastructure with built-in canary analysis, automated verification and one-click rollback, plus native Argo CD-based GitOps.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Feature Flags$q$, $q$Progressive delivery and experimentation platform for toggling features and running A/B tests without redeploying code.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Security Testing Orchestration$q$, $q$Aggregates and de-duplicates findings from static, dynamic and software composition analysis scanners into a single prioritized governance view.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Chaos Engineering$q$, $q$Runs controlled resilience experiments built on the open-source LitmusChaos project to validate how systems behave under failure conditions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Cloud Cost Management$q$, $q$Tracks Kubernetes and cloud spend, automates rightsizing recommendations and helps plan reserved capacity commitments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Infrastructure as Code Management$q$, $q$Applies policy-as-code checks to Terraform and OpenTofu plans before they run, with drift detection and cost estimation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Unified Governance and Audit$q$, $q$A shared RBAC model, audit log and Open Policy Agent-based policy layer spans every module for consistent compliance across the delivery lifecycle.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Consolidates CI, CD, feature flags, security testing, chaos engineering and cost management on one platform with shared governance$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Per-developer pricing model is simpler to budget than per-seat-per-module pricing used by many competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Strong Kubernetes-native deployment strategies including canary analysis and automated rollback$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Free and open-source entry points (Harness CI, Litmus Chaos) lower the barrier for smaller teams to try the platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Generative AI features for pipeline authoring and failure triage reduce manual pipeline maintenance$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Full enterprise pricing is not published and typically requires a sales conversation, making budgeting difficult upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Breadth of modules can mean a learning curve for teams that only need one or two capabilities$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Some users report the UI and module navigation feels complex compared to single-purpose tools like CircleCI$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Migrating existing Jenkins or Spinnaker pipelines to Harness requires nontrivial reconfiguration effort$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Advanced governance and on-premises deployment are reserved for the Enterprise tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$What is Harness used for$q$, $q$Harness is used to automate and govern software delivery, covering continuous integration, continuous deployment, feature flag rollouts, security scan orchestration, chaos testing and cloud cost optimization from one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Is Harness free to use$q$, $q$Yes, Harness offers a Free plan with open-source starter capabilities such as Harness CI and Litmus Chaos. Paid Essentials and Enterprise plans unlock higher usage limits and additional modules.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Who founded Harness$q$, $q$Harness was founded in 2017 by Jyoti Bansal and Rishi Singh, incubated inside Bansal's startup studio BIG Labs after he sold his previous company AppDynamics to Cisco.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$How is Harness priced$q$, $q$Harness uses per-developer modular pricing across three tiers: Free, Essentials and Enterprise. Essentials and Enterprise pricing is quote-based and depends on which modules and usage limits an organization needs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Does Harness replace Jenkins$q$, $q$Harness can replace Jenkins for continuous integration and adds continuous delivery, feature flags, security testing and other modules on top, though migrating existing Jenkins pipelines requires reconfiguration.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$What is Harness Chaos Engineering built on$q$, $q$Harness Chaos Engineering is built on LitmusChaos, an open-source chaos engineering project that Harness maintains and contributes to.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Kubernetes deployment automation$q$, $q$Platform engineering teams use Harness Continuous Delivery to automate canary and blue-green deployments to Kubernetes with automated rollback if verification fails.$q$, $q$Platform and DevOps engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Consolidating a fragmented DevOps toolchain$q$, $q$Organizations running separate Jenkins, Argo CD, LaunchDarkly and Snyk instances migrate onto Harness to unify pipelines, governance and audit trails under one platform.$q$, $q$Engineering leaders and enterprise IT$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Cloud cost optimization for Kubernetes workloads$q$, $q$FinOps and infrastructure teams use Harness Cloud Cost Management to identify overprovisioned workloads and automate rightsizing to reduce cloud spend.$q$, $q$FinOps and infrastructure teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source starter platform (Harness CI, Litmus Chaos)","Community support","Limited usage suitable for individuals and small teams"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Essentials$q$, $q$Contact sales$q$, $q$Annual$q$, NULL, $q$["Bundled CI, CD, Code Repository, STO and IaCM modules","Up to 500 users and 1 organization","Up to 5 custom dashboards","Up to 60 concurrent pipeline executions","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Full module catalog available a la carte","Unlimited users, organizations, dashboards and concurrent executions","Premium support with dedicated account manager","Optional on-premises or self-managed deployment"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Harness is a modular software delivery platform that combines CI/CD, feature flags, security testing orchestration, chaos engineering, cloud cost management and infrastructure as code governance under one roof. Founded in 2017 by Jyoti Bansal (co-founder of AppDynamics) and Rishi Singh, it was built to give engineering organizations a single, policy-governed pipeline engine instead of stitching together separate point tools for every stage of the delivery lifecycle.$q$, $q$The platform runs on Kubernetes and is available as SaaS or as a self-managed enterprise deployment. Each module (CI, CD/GitOps, Feature Flags, STO, CCM, SRM, Chaos Engineering, IaCM) can be adopted independently but shares a common pipeline engine, RBAC model, audit trail and policy-as-code layer, which is the core reason large engineering teams consolidate onto Harness rather than running Jenkins, Argo CD, LaunchDarkly and Snyk separately.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Harness Continuous Integration provides cloud-hosted or self-hosted build infrastructure with caching, test intelligence (running only tests affected by a code change), and parallelization to cut build times. Harness Continuous Delivery and GitOps supports Kubernetes, VM, serverless and traditional deployment targets with built-in canary analysis, automated rollback and native Argo CD-based GitOps workflows.$q$, $q$Feature Flags enables progressive delivery and A/B testing without redeploying code, while Security Testing Orchestration aggregates, de-duplicates and prioritizes findings from static analysis, dynamic analysis and software composition analysis tools into one governance view. Chaos Engineering, built on the open-source LitmusChaos project, lets teams run controlled resilience experiments against production-like environments.$q$, $q$Cloud Cost Management gives visibility into Kubernetes and cloud spend with automated rightsizing and commitment planning, Service Reliability Management tracks SLOs and error budgets, and Infrastructure as Code Management governs Terraform and OpenTofu plans with policy checks before they apply. Generative AI features layered across these modules can draft pipeline YAML, summarize failed builds, and suggest fixes.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Harness prices per developer rather than per build minute, with three tiers. The Free plan gives individuals and small teams access to open-source starter capabilities including Harness CI and Litmus Chaos at no cost. The Essentials plan bundles core modules (CI, CD, Code Repository, STO, IaCM) for growing teams, capped at 500 users, one organization and 60 concurrent pipeline executions, priced via a sales quote.$q$, $q$The Enterprise plan removes all caps, unlocks the full module catalog, and adds premium support with a dedicated account manager plus an optional on-premises deployment add-on. Published third-party pricing data puts the median annual contract around 49,000 dollars, with multi-year prepayment commonly discounted 15 to 30 percent.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
