INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82b1ccc3-3f53-4e7a-8f43-b0c0dcbf7a7f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Time Tracking$q$, $q$One-click timers with idle detection across web, Mac, Windows, iOS, Android and a browser extension, all syncing in real time.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Invoicing$q$, $q$Generates professional invoices directly from tracked time and expenses, with online payment collection via Stripe, PayPal and other processors.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Project Budgeting and Profitability Reports$q$, $q$Visual dashboards show budget burn, team capacity and project profitability so managers can catch scope creep early.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Expense Tracking$q$, $q$Employees can photograph receipts from the mobile app and attach expenses directly to client projects and invoices.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Timesheet Approvals$q$, $q$Managers can review and approve submitted timesheets before they are billed, available on Enterprise and above.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Accounting Integrations$q$, $q$Native integrations with QuickBooks, Xero and Deel keep invoicing and payroll data synced without manual entry.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Team Reporting$q$, $q$Aggregated reporting across projects and team members highlights utilization and capacity trends.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Single Sign-On and Activity Log$q$, $q$SAML-based SSO and a detailed activity log support security and compliance requirements for larger organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Long track record of reliability and a clean, minimal interface focused on the time-to-invoice workflow$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Free plan available for solo freelancers, plus a 30-day trial on all paid tiers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Deep integrations with accounting tools like QuickBooks, Xero and Deel$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Strong multi-platform coverage with native Mac, Windows, iOS and Android apps$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Visual project profitability and budget reports are useful for agencies billing clients hourly$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Post-acquisition pricing restructure introduced usage-based fees that have increased costs for some high-usage accounts$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Not a full project management suite, so teams needing task management must pair it with another tool$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Fewer advanced resource-planning features than dedicated agency management platforms like Productive.io$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Enterprise-tier features such as SSO and profitability reporting require the higher-priced plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$2025 acquisition by Bending Spoons has raised uncertainty among long-time users about future pricing and roadmap direction$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$What is Harvest used for$q$, $q$Harvest is used for time tracking, invoicing and expense management, letting freelancers and teams log billable hours and convert them directly into client invoices.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Is Harvest free to use$q$, $q$Harvest has a permanently free plan limited to one seat and two projects. Paid plans start at 9 dollars per seat per month and include a 30-day free trial.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Who owns Harvest now$q$, $q$Harvest was acquired by Bending Spoons, an Italian technology holding company, in June 2025, after operating as an independent bootstrapped company since 2006.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Does Harvest have a mobile app$q$, $q$Yes, Harvest offers native iOS and Android apps for tracking time and capturing expense receipts on the go, alongside Mac and Windows desktop apps.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$What integrations does Harvest support$q$, $q$Harvest integrates with project tools like Asana, Trello and Slack, accounting platforms including QuickBooks and Xero, payroll tool Deel, and payment processors like Stripe and PayPal.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Who founded Harvest$q$, $q$Harvest was founded in 2006 by Danny Wen and Shawn Liu, who built it to solve time-tracking and invoicing problems at their own web design agency, Iridesco, in New York City.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Freelancer time tracking and invoicing$q$, $q$Independent freelancers track billable hours against client projects and generate invoices with online payment collection, all on the free or Teams plan.$q$, $q$Freelancers and solo consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Agency project profitability tracking$q$, $q$Creative and marketing agencies use Harvest's budget and profitability reports to see which client projects are running over budget in real time.$q$, $q$Creative and marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Professional services timesheet approval$q$, $q$Consulting firms use Enterprise-tier timesheet approval workflows and SSO to enforce billing accuracy and security compliance before invoicing clients.$q$, $q$Professional services and consulting firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Free$q$, $q$$0$q$, $q$Forever$q$, NULL, $q$["1 seat","2 projects","Time tracking, invoicing and expense tracking","Mac and iOS apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Teams$q$, $q$$9/seat/month ($108/seat billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited seats","Team reporting","Accounting and payment integrations (Stripe, QuickBooks, Xero, Deel)","30-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Enterprise$q$, $q$$14/seat/month ($168/seat billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited custom reports","Profitability reporting","Timesheet approvals","SAML-based single sign-on","Activity log"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$Enterprise Plus$q$, $q$Custom pricing$q$, $q$Negotiated$q$, NULL, $q$["Custom integrations","Product customization","White-labeling","Dedicated success manager","Assisted data migration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Harvest is a time tracking, invoicing and expense management tool created in 2006 by Danny Wen and Shawn Liu to solve billing problems at their own New York City web design agency, Iridesco. It grew into a widely used bootstrapped SaaS product before being acquired by Bending Spoons in June 2025.$q$, $q$The product focuses narrowly on the time-to-invoice workflow: log hours against clients and projects from web, desktop, mobile or browser extension apps, review profitability and budget-burn reports, and generate invoices that clients can pay online, rather than trying to be a full project management suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include one-click and idle-detection timers, visual project budget and profitability dashboards, and customizable exportable reports for team and client-level analysis. Invoicing supports online payment collection through Stripe, PayPal and other processors, and expense tracking allows receipt photo uploads from the mobile app.$q$, $q$Higher tiers add timesheet approval workflows for managers, SAML-based single sign-on, and detailed activity logs for compliance. Harvest integrates with project tools like Asana, Trello and Slack, and accounting platforms including QuickBooks, Xero and Deel, plus a public API for custom connections.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Harvest offers a permanently free plan for one seat and two projects. The Teams plan costs 9 dollars per seat per month (108 dollars per seat annually with a 20 percent discount) and adds unlimited seats and team reporting. The Enterprise plan costs 14 dollars per seat per month (168 dollars annually) and adds profitability reporting, approvals and SSO.$q$, $q$Since the 2025 Bending Spoons acquisition, paid plans also carry usage-based charges layered on top of the per-seat base rate for additional invoices, projects, clients and tasks. An Enterprise Plus tier offers custom pricing with white-labeling and a dedicated success manager for large organizations, and all paid plans include a 30-day free trial.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8b4bc6ea-bad2-4c99-9750-883f839aa67e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
