INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82ee8074-8c82-4567-87cf-e4ee7c5da225', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82ee8074-8c82-4567-87cf-e4ee7c5da225', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82ee8074-8c82-4567-87cf-e4ee7c5da225', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82ee8074-8c82-4567-87cf-e4ee7c5da225', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Automated ActivityPub Actor Creation$q$, $q$Generates ActivityPub profiles automatically from a static site's existing content feed without requiring HTML markup changes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Feed-Based Data Source$q$, $q$Reads JSON Feed, Atom or RSS as its source of truth instead of requiring microformats2-annotated HTML pages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Fediverse Search Redirection$q$, $q$Redirects Fediverse searches for site pages or authors to the corresponding Hatsu-hosted profile or post.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Follower Management and Post Distribution$q$, $q$Accepts follow requests from Fediverse users and automatically distributes new posts to followers when the site feed updates.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Reply Backfeeding$q$, $q$Collects replies posted by Fediverse users and feeds them back to the static site so conversations can be displayed on the original page.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$HTTP Signature Security$q$, $q$Implements cryptographic HTTP signature verification for secure, spoofing-resistant server-to-server federation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Mastodon and GoToSocial Compatibility$q$, $q$Supports Mastodon's secure mode and interoperates with GoToSocial for broader Fediverse platform compatibility.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Lightweight Rust Runtime with Docker Deployment$q$, $q$Built in Rust with aarch64 support and straightforward Docker-based self-hosting for low-resource environments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Completely free and open source with no subscription cost or vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Works with any static site generator that produces a JSON Feed, Atom or RSS feed, not tied to one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Written in Rust for a lightweight, low-resource footprint suitable for modest self-hosted servers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Automates backfeeding of Fediverse replies, a capability many manual Webmention-based approaches lack$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Actively maintained with regular releases and a public GitHub issue tracker for support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Requires self-hosting and server administration skills, with no managed hosting option available$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Small project with a modest GitHub following, so community support and third-party tutorials are limited$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$ActivityPub-only, meaning it does not bridge to other decentralized protocols like Nostr or AT Protocol (Bluesky)$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$AGPLv3 license requires anyone distributing modified versions as a network service to release their source changes$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$No official commercial support channel exists for organizations needing SLA-backed assistance$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$What is Hatsu used for$q$, $q$Hatsu is used to let a static website participate in the Fediverse, allowing Mastodon and other ActivityPub users to follow the site, see new posts, and reply, without the site needing a dynamic backend.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Is Hatsu free to use$q$, $q$Yes, Hatsu is completely free and open source under the AGPLv3 license. There are no subscription plans; operators only pay for the server infrastructure they self-host it on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Does Hatsu work with any static site generator$q$, $q$Yes, Hatsu works with any static site that produces a JSON Feed, Atom or RSS feed, including sites built with Hugo, Jekyll, Eleventy and Astro, since it reads the feed rather than requiring specific HTML markup.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$What programming language is Hatsu written in$q$, $q$Hatsu is written primarily in Rust, built on the Activitypub-Federation-Rust library, the same library used by the federated platform Lemmy.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Does Hatsu support protocols other than ActivityPub$q$, $q$No, Hatsu is ActivityPub-only and does not bridge to other decentralized protocols such as Nostr or AT Protocol (Bluesky).$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$How is Hatsu different from Bridgy Fed$q$, $q$Hatsu is self-hosted, giving operators full control over their own instance, while Bridgy Fed is a hosted third-party service that performs a broadly similar bridging function without requiring self-hosting.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Federating a personal blog with Mastodon$q$, $q$Bloggers using static site generators like Hugo or Eleventy deploy Hatsu so Mastodon users can follow their blog and see new posts appear in their Fediverse timeline.$q$, $q$Independent bloggers and static-site publishers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Enabling Fediverse replies on static documentation or portfolio sites$q$, $q$Site owners use Hatsu's backfeeding feature to surface Mastodon replies and discussion directly on their static pages without building comment infrastructure.$q$, $q$Developers and technical writers running static sites$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Self-hosted alternative to third-party Fediverse bridging services$q$, $q$Privacy-conscious operators who do not want to rely on a hosted third-party bridge self-host Hatsu to keep full control over their federation infrastructure.$q$, $q$Self-hosting enthusiasts and privacy-focused site owners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full ActivityPub bridging functionality","Self-hosted via Docker","Community support via GitHub","AGPLv3 licensed source code"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hatsu is a self-hosted, fully automated ActivityPub bridge that lets static websites federate with the Fediverse, the decentralized social network underlying platforms like Mastodon and GoToSocial, without adding a dynamic backend to the site itself. It reads a site's existing JSON Feed, Atom or RSS feed and uses that as its data source, rather than requiring HTML markup changes.$q$, $q$The project is written primarily in Rust, built on the Activitypub-Federation-Rust library also used by Lemmy, and is maintained by a GitHub developer known as importantimport under the AGPLv3 open-source license.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hatsu automatically creates ActivityPub actor profiles from a site's feed, redirects Fediverse searches for site pages or authors to the corresponding Hatsu-hosted profile, and accepts and distributes follower relationships as the feed updates with new posts.$q$, $q$It backfeeds replies from Fediverse users to the static site so Fediverse conversations can surface on the original content, implements HTTP signature verification for secure federation, and supports compatibility modes for Mastodon's secure mode and GoToSocial. Deployment is Docker-based for straightforward self-hosting, with aarch64 support for lower-powered hardware.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hatsu is entirely free and open source under the AGPLv3 license, with no company, subscription plans or paid tiers behind it.$q$, $q$The only costs involved are the server infrastructure an operator chooses to self-host Hatsu on and the time needed to configure DNS, reverse proxying and the feed source, since there is no managed hosting option or commercial support offering.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3ef53b6f-d698-4b20-ab83-57c388a50f2d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
