-- ── Harvey ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Enterprise AI platform for legal and professional services, offering domain-specific AI for legal research, contract analysis, drafting and workflow automation.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise, custom per-seat annual contracts$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (contact sales)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Harvey Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Harvey is an enterprise AI platform for law firms and legal teams. See its features, pricing, funding, pros, cons and alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Harvey is an enterprise artificial intelligence platform purpose-built for legal and professional services work, offering domain-specific AI tools for legal research, contract analysis, document drafting, due diligence and litigation support. Rather than positioning itself as a general-purpose chatbot with a legal skin, Harvey is built around workflows that mirror how lawyers actually work: analyzing large volumes of documents, cross-referencing case law and regulation, drafting and redlining contracts, and producing memos and briefs that meet the evidentiary and citation standards legal professionals require. The platform is organized into several product modules, including Assistant for open-ended legal question answering and drafting, Vault for secure storage and bulk analysis of large legal document sets, Knowledge for researching complex legal, regulatory and tax questions across jurisdictions, Workflow Agents for automating multi-step processes like due diligence review, Contract Intelligence for extracting key terms and clauses from agreements, and a Command Center that gives firm leadership usage analytics and benchmarking to guide AI adoption. Harvey was founded in the summer of 2022 by Winston Weinberg, a former securities and antitrust litigator at law firm O'Melveny and Myers, and Gabriel Pereyra, a research scientist with a background at Google DeepMind and Meta. The pairing of a practicing litigator with a machine learning researcher shaped Harvey's core thesis from day one: general-purpose large language models were not, on their own, reliable or trustworthy enough for legal work without domain-specific fine-tuning, retrieval infrastructure and rigorous evaluation built specifically around legal accuracy and citation integrity. Harvey's earliest funding, a 5 million dollar round in November 2022, was notably led by the OpenAI Startup Fund, and the company has maintained a close model relationship with OpenAI while also incorporating models from other providers over time. Harvey's funding trajectory since then has been unusually fast even by generative AI startup standards: an 80 million dollar Series B in December 2023 led by Kleiner Perkins and Elad Gil valued the company at 715 million dollars; a 100 million dollar Series C in July 2024 led by GV (Google Ventures), with participation from OpenAI, Kleiner Perkins and Sequoia Capital, pushed the valuation to 1.5 billion dollars; and by March 2026 Harvey had raised 200 million dollars in a round co-led by GIC and Sequoia Capital at an 11 billion dollar valuation, roughly four years after founding. Total funding raised across all rounds is reported at approximately 1.22 billion dollars, from an investor roster that includes Sequoia Capital, Kleiner Perkins, Andreessen Horowitz, GV, Elad Gil and the OpenAI Startup Fund. The company is headquartered in San Francisco and reports serving more than 1,000 clients globally, including roughly half of the Am Law 100 (the 100 largest US law firms by revenue), as well as corporate legal departments, tax and accounting firms, and government agencies; by its own published figures the platform processes over 850,000 queries and more than 50 million files per day across its customer base. Harvey does not publish list pricing on its website; instead, enterprise contracts are negotiated individually based on firm size, seat count and which modules are licensed. Third-party market intelligence estimates place per-seat costs in the range of 1,000 to 1,200 dollars per month, or roughly 12,000 to 16,800 dollars per seat annually depending on whether the base package or a premium bundle is selected, with most engagements requiring a minimum of 25 to 50 or more lawyer seats. That structure typically results in total annual contract values ranging from about 30,000 dollars for smaller firm deployments up to several hundred thousand dollars or more for large Am Law 100 firms, sold through six-month-plus enterprise sales cycles rather than self-serve checkout. Harvey's target audience is squarely large law firms, in-house corporate legal departments, and other professional services organizations (accounting, tax and consulting firms) that handle high volumes of document-intensive, precision-critical work and have the budget for enterprise AI deployment with dedicated account management and custom integrations into firm document management systems. Its competitive set includes other legal-specific AI vendors such as CoCounsel (Thomson Reuters, formerly Casetext), Robin AI, Lexis+ AI, Spellbook, and Legora, as well as generic enterprise AI assistants that firms sometimes evaluate as cheaper alternatives; Harvey differentiates through its litigator-plus-researcher founding team, its deep integrations and workflow customization for large firms, its very high-profile investor base including OpenAI itself, and market-leading adoption among the largest US law firms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '27da3ffe-16ca-4435-8f4c-af4532ecfbcd';

