-- ── Hatsu ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Self-hosted, fully automated ActivityPub bridge written in Rust that lets any static site federate with the Fediverse without adding a dynamic backend.$q$, short_description),
  pricing_model = COALESCE($q$Open Source, free$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Hatsu Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Hatsu is an open-source, self-hosted ActivityPub bridge for static sites. See its features, setup requirements, pros, cons and alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Hatsu is a self-hosted, fully automated ActivityPub bridge that lets any static website participate in the Fediverse, the decentralized social network built on the ActivityPub protocol that underpins platforms like Mastodon and GoToSocial, without requiring the site itself to run a dynamic backend or implement federation logic. Static site generators such as Hugo, Jekyll, Eleventy and Astro produce plain HTML files with no server-side application to handle incoming ActivityPub requests, follow relationships, or replies from Fediverse users, so historically the only ways to federate a static site were either to bolt on a separate dynamic service or to implement Webmention-based interoperability manually, both of which add operational complexity. Hatsu solves this by running as its own lightweight server process alongside (or in front of) the static site: it reads the site's existing content feed in JSON Feed, Atom or RSS format, rather than requiring the site to add microformats2 markup to its HTML, and from that feed it automatically creates and maintains ActivityPub actor profiles that Fediverse users can discover and follow. When someone on Mastodon or another ActivityPub-compatible platform searches for a page on the underlying static site or for one of its authors, Hatsu transparently redirects that search to the corresponding Hatsu-hosted profile or post, handles the incoming follow request, distributes new posts to followers automatically when the site's feed updates, and, critically, backfeeds replies from Fediverse users to the static site so that Fediverse-native conversation threads can be surfaced back on the original site. All of this happens without the site owner needing to manually send or process Webmentions, and without modifying the static site's HTML templates to include federation markup, since Hatsu relies entirely on the machine-readable feed as its data source. The project is developed by a GitHub user and maintainer known as importantimport, and is hosted publicly at github.com/importantimport/hatsu; it is written primarily in Rust (accounting for the large majority of the codebase), which the project cites as a deliberate choice for performance and for enabling deployment on lower-powered hardware, including aarch64-based devices, alongside straightforward Docker-based self-hosting. Hatsu builds on the Activitypub-Federation-Rust library, the same underlying Rust ActivityPub implementation used by Lemmy, the federated link-aggregation platform, which gives Hatsu a battle-tested foundation for handling the cryptographic HTTP signature verification and federation protocol details that ActivityPub requires for secure, spoofing-resistant communication between servers. The project explicitly supports compatibility features such as Mastodon's secure mode and GoToSocial interoperability, and documents redirecting via both static files and markup for site owners who want more control over how their pages resolve to Hatsu profiles. As of mid-2026 the project has accumulated a modest but active following on GitHub, with around 256 stars, 8 forks and 33 tagged releases, the most recent in December 2025, indicating a small, focused, actively maintained open-source project rather than a large commercial product. Hatsu is licensed under the GNU Affero General Public License version 3 (AGPLv3), a copyleft license that requires anyone who modifies and distributes the software, including running a modified version as a network service, to make their source code changes available, consistent with its lineage from the AGPL-licensed Lemmy codebase. Because it is entirely open source with no company, funding or commercial entity behind it, Hatsu has no pricing tiers, subscription plans or paid support offering; it is free to download, self-host and modify, with the only cost being the server infrastructure an operator chooses to run it on and the time required to configure DNS, reverse proxying and the feed source correctly. Hatsu's target audience is technically inclined bloggers, independent publishers and static-site-generator users who want their content and its authors to be discoverable and followable on Mastodon and other Fediverse platforms without abandoning the simplicity, cost and performance benefits of a fully static site. Its closest points of comparison are Bridgy Fed, a hosted (non-self-hosted) service that performs a broadly similar function of bridging websites, blogs and other protocols into the Fediverse, and WordPress's official ActivityPub plugin, which serves a similar purpose but only for WordPress-powered dynamic sites; Hatsu differentiates by being self-hosted rather than a third-party hosted dependency, by working from any feed-producing static site generator rather than being tied to one platform, and by being written in Rust for a lightweight, low-resource footprint suitable for running on modest self-hosted infrastructure.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3ef53b6f-d698-4b20-ab83-57c388a50f2d';

